// TestAuditRecordedFiles_StaleHomeEntriesAreNoOp verifies that pre-migration
// InstalledEntry records with ~/... Files paths do not produce audit issues
// when the expanded paths do not exist on disk.

package registry

import (
	"fmt"
	"io/fs"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/skills"
)

// AuditInstalledEntry checks one installed package entry for plugin issues.
func AuditInstalledEntry(entry InstalledEntry, fallback *Package) []ValidationIssue {
	var issues []ValidationIssue
	root := installedRootPath(entry)
	if root == "" {
		issues = append(issues, ValidationIssue{Message: fmt.Sprintf("installed entry %q has no recorded plugin root", entry.Name)})
		return issues
	}

	issues = append(issues, auditRecordedFiles(entry)...)

	manifest, manifestMissing, manifestIssues := loadPackageDefinitionForAudit(root, fallback)
	issues = append(issues, manifestIssues...)

	if manifestMissing {
		issues = append(issues, ValidationIssue{
			Path:    filepath.Join(root, "package.yaml"),
			Message: "missing package.yaml",
		})
	}

	if manifest == nil {
		manifest = &Package{}
	}

	issues = append(issues, ValidatePackageStructure(root, manifest)...)
	return issues
}

// ValidatePackageStructure checks the skill, symlink, and executable layout
// for a package root before install or after install-state recovery.
func ValidatePackageStructure(root string, pkg *Package) []ValidationIssue {
	if pkg == nil {
		return []ValidationIssue{{Path: filepath.Join(root, "package.yaml"), Message: "missing package definition"}}
	}
	return auditPluginRoot(root, pkg)
}

func loadPackageDefinitionForAudit(root string, fallback *Package) (*Package, bool, []ValidationIssue) {
	manifest, manifestMissing, issues, err := LoadPackageManifestWithFallback(root, fallback)
	if err == nil || os.IsNotExist(err) {
		// Report validation issues even when package is valid, so audit shows schema problems.
		return manifest, manifestMissing, issues
	}

	// If a partial package was returned (YAML parsed but validation issues exist),
	// return it with the issues so structural audits can proceed.
	if manifest != nil {
		return manifest, false, issues
	}

	if len(issues) == 0 {
		issues = append(issues, ValidationIssue{Path: filepath.Join(root, "package.yaml"), Message: err.Error()})
	}
	return manifest, false, issues
}

func auditPluginRoot(root string, pkg *Package) []ValidationIssue {
	var issues []ValidationIssue

	if pkg.APIVersion != "" && pkg.APIVersion != SupportedPackageAPIVersion {
		issues = append(issues, ValidationIssue{
			Path:    filepath.Join(root, "package.yaml"),
			Message: fmt.Sprintf("unsupported `api_version` %q (supported: %s)", pkg.APIVersion, SupportedPackageAPIVersion),
		})
	}

	ignoredBrokenSymlinkPaths := collectIgnoredBrokenSymlinkPaths(root, pkg)
	for _, symlinkIssue := range auditBrokenSymlinks(root, ignoredBrokenSymlinkPaths) {
		issues = append(issues, symlinkIssue)
	}

	for _, skillRoot := range collectSkillRoots(root, pkg) {
		issues = append(issues, auditSkillRoot(root, skillRoot)...)
	}

	for _, rel := range pkg.Install.Executable {
		issues = append(issues, auditExecutable(root, rel)...)
	}

	return issues
}

func auditRecordedFiles(entry InstalledEntry) []ValidationIssue {
	var issues []ValidationIssue
	seen := map[string]bool{}
	recordedPaths := append([]string(nil), entry.Files...)
	if root := installedRootPath(entry); root != "" {
		recordedPaths = append(recordedPaths, root)
	}
	for _, recorded := range recordedPaths {
		path := ExpandHome(recorded)
		if path == "" || seen[path] {
			continue
		}
		seen[path] = true
		info, err := os.Lstat(path)
		if err != nil {
			if os.IsNotExist(err) {
				// Pre-migration entries whose paths begin with ~ are outside the
				// project root; treat missing paths as no-op (no issue raised).
				if strings.HasPrefix(recorded, "~") {
					continue
				}
				issues = append(issues, ValidationIssue{Path: path, Message: "missing recorded file or symlink"})
				continue
			}
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			continue
		}
		if info.Mode()&os.ModeSymlink == 0 {
			continue
		}

		target, err := os.Readlink(path)
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
			continue
		}
		if !filepath.IsAbs(target) {
			target = filepath.Join(filepath.Dir(path), target)
		}
		if _, err := os.Stat(target); err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
		}
	}
	return issues
}

func auditBrokenSymlinks(root string, ignored map[string]bool) []ValidationIssue {
	var issues []ValidationIssue
	walkRoot := root
	if resolved, err := filepath.EvalSymlinks(root); err == nil && resolved != "" {
		walkRoot = resolved
	}

	_ = filepath.WalkDir(walkRoot, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			return nil
		}
		if path == walkRoot {
			return nil
		}

		info, err := os.Lstat(path)
		if err != nil {
			if os.IsNotExist(err) {
				issues = append(issues, ValidationIssue{Path: path, Message: "missing installed file"})
				return nil
			}
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			return nil
		}
		if info.Mode()&os.ModeSymlink == 0 {
			return nil
		}
		if ignored != nil && ignored[path] {
			return nil
		}

		target, err := os.Readlink(path)
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
			return nil
		}
		if !filepath.IsAbs(target) {
			target = filepath.Join(filepath.Dir(path), target)
		}
		if _, err := os.Stat(target); err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
		}
		return nil
	})

	return issues
}

func collectSkillRoots(root string, pkg *Package) []string {
	seen := map[string]bool{}
	var roots []string

	add := func(candidate string) {
		if strings.TrimSpace(candidate) == "" {
			return
		}
		abs := candidate
		if resolved, err := filepath.EvalSymlinks(candidate); err == nil && resolved != "" {
			abs = resolved
		} else if resolved, err := filepath.Abs(candidate); err == nil && resolved != "" {
			abs = resolved
		}
		if seen[abs] {
			return
		}
		if _, err := os.Stat(candidate); err != nil {
			return
		}
		seen[abs] = true
		roots = append(roots, candidate)
	}

	for _, mapping := range pkg.Install.Skills {
		sourceRoot := filepath.Join(root, filepath.FromSlash(mapping.Source))
		add(sourceRoot)

		cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
		switch cleanSource {
		case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
			add(filepath.Join(root, "skills"))
		}
	}

	return roots
}

func collectIgnoredBrokenSymlinkPaths(root string, pkg *Package) map[string]bool {
	ignored := make(map[string]bool)
	for _, mapping := range pkg.Install.Skills {
		cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
		switch cleanSource {
		case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
			skillRoot := filepath.Join(root, cleanSource)
			entries, err := os.ReadDir(skillRoot)
			if err != nil {
				continue
			}
			for _, entry := range entries {
				ignored[filepath.Join(skillRoot, entry.Name())] = true
			}
		}
	}
	return ignored
}

func auditSkillRoot(packageRoot, root string) []ValidationIssue {
	var issues []ValidationIssue

	info, err := os.Stat(root)
	if err != nil {
		issues = append(issues, ValidationIssue{Path: root, Message: err.Error()})
		return issues
	}
	if !info.IsDir() {
		issues = append(issues, ValidationIssue{Path: root, Message: "expected a skill directory"})
		return issues
	}

package graphql

import (
	"context"
	"fmt"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// RunRequeueEventKind is the BeadEvent.Kind appended to the originating bead's
// audit log every time runRequeue successfully re-queues that bead. The body
// captures operator identity, the run id under attempt, the optional layer
// override, and the idempotency key so duplicate-key collapses are traceable.
const RunRequeueEventKind = "run_requeue"

// RunRequeue implements the runRequeue mutation: given a runId, look up the
// originating bead, atomically dedupe by idempotencyKey, reopen the bead so
// the execute-loop can claim it again, and append an audit event capturing
// operator identity. Concurrent calls with the same idempotencyKey collapse
// to a single re-queue (the second caller receives deduplicated=true and the
// same bead).
func (r *mutationResolver) RunRequeue(ctx context.Context, input RunRequeueInput) (*RunRequeueResult, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}
	if strings.TrimSpace(input.RunID) == "" {
		return nil, fmt.Errorf("runRequeue: runId is required")
	}
	if strings.TrimSpace(input.IdempotencyKey) == "" {
		return nil, fmt.Errorf("runRequeue: idempotencyKey is required")
	}

	cache := r.RunRequeueIdempotency
	if cache == nil {
		return nil, fmt.Errorf("runRequeue: idempotency cache not configured")
	}

	provider, ok := r.State.(RunsStateProvider)
	if !ok {
		return nil, fmt.Errorf("runRequeue: runs state provider not configured")
	}
	run, ok := provider.GetRunGraphQL(input.RunID)
	if !ok || run == nil {
		return nil, fmt.Errorf("runRequeue: run %s not found", input.RunID)
	}
	if run.BeadID == nil || *run.BeadID == "" {
		return nil, fmt.Errorf("runRequeue: run %s has no originating bead", input.RunID)
	}
	originatingBeadID := *run.BeadID

	store := r.beadStore(ctx)

	// Atomic claim block: serialize lookup+reserve+store so concurrent calls
	// with the same idempotencyKey collapse to a single re-queue. The store's
	// per-bead Update is itself atomic; this mutex covers the cache plus the
	// audit event so duplicate keys never produce two reopen+event pairs.
	r.runRequeueMu.Lock()
	defer r.runRequeueMu.Unlock()

	if cachedID, hit := cache.Lookup(input.IdempotencyKey); hit {
		// A prior call under this key already requeued a bead. Return that
		// bead unchanged regardless of its current lifecycle status —
		// "duplicate-key returns existing requeued bead, not error".
		if existing, err := store.Get(cachedID); err == nil {
			return &RunRequeueResult{
				Bead:         beadModelFromBead(existing),
				Deduplicated: true,
			}, nil
		}
		// The cached id points at a missing bead — fall through and replay
		// the requeue against the run's current originating bead.
	}

	if err := store.Update(originatingBeadID, func(b *bead.Bead) {
		b.Status = bead.StatusOpen
		b.Owner = ""
	}); err != nil {
		return nil, fmt.Errorf("runRequeue: reopen bead %s: %w", originatingBeadID, err)
	}

	identity := operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
	if httpReq := httpRequestFromContext(ctx); httpReq != nil {
		identity = operatorPromptIdentity(httpReq)
	}
	layerOverride := ""
	if input.Layer != nil {
		layerOverride = *input.Layer
	}
	auditBody := fmt.Sprintf(
		"identity=%s actor=%s run_id=%s idempotency_key=%s layer_override=%s",
		identity.kind,
		identity.actor,
		input.RunID,
		input.IdempotencyKey,
		layerOverride,
	)
	if err := store.AppendEvent(originatingBeadID, bead.BeadEvent{
		Kind:    RunRequeueEventKind,
		Summary: "run requeued",
		Body:    auditBody,
		Actor:   identity.actor,
		Source:  "graphql:runRequeue",
	}); err != nil {
		return nil, fmt.Errorf("runRequeue: append audit event: %w", err)
	}

	cache.Store(input.IdempotencyKey, originatingBeadID)

	persisted, err := store.Get(originatingBeadID)
	if err != nil {
		return nil, err
	}
	return &RunRequeueResult{
		Bead:         beadModelFromBead(persisted),
		Deduplicated: false,
	}, nil
}

package graphql

import (
	"context"
	"fmt"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// RunsStateProvider is the optional sub-interface a StateProvider may
// implement to back the runs/run queries.
// Kept separate from StateProvider so test stubs that don't need runs
// continue to compile.
type RunsStateProvider interface {
	GetRunsGraphQL(projectID string, filter RunFilter) []*Run
	GetRunGraphQL(id string) (*Run, bool)
}

// RunDetailStateProvider is the optional sub-interface for the Story 16
// run-detail surfaces (tool calls + bundle file resolver). Kept separate from
// RunsStateProvider so legacy stubs continue to compile.
type RunDetailStateProvider interface {
	GetRunToolCallsGraphQL(id string) []*RunToolCall
	GetRunBundleFileGraphQL(id, path string) (*RunBundleFileContent, bool)
}

const runDetailViewEventKind = "run_detail_view"

// RunFilter holds the optional filter args for Query.runs.
type RunFilter struct {
	Layer   *RunLayer
	BeadID  string
	Status  string
	Harness string
}

// Runs is the resolver for the runs field.
func (r *queryResolver) Runs(ctx context.Context, projectID *string, layer *RunLayer, beadID *string, status *string, harness *string, first *int, after *string) (*RunConnection, error) {
	provider, ok := r.State.(RunsStateProvider)
	if !ok {
		return emptyRunConnection(), nil
	}
	pid := ""
	if projectID != nil {
		pid = *projectID
	}
	filter := RunFilter{Layer: layer}
	if beadID != nil {
		filter.BeadID = *beadID
	}
	if status != nil {
		filter.Status = *status
	}
	if harness != nil {
		filter.Harness = *harness
	}
	all := provider.GetRunsGraphQL(pid, filter)
	return runConnectionFrom(all, first, after), nil
}

// Run is the resolver for the run field.
func (r *queryResolver) Run(ctx context.Context, id string) (*Run, error) {
	provider, ok := r.State.(RunsStateProvider)
	if !ok {
		return nil, nil
	}
	wd := r.workingDir(ctx)
	if wd == "" {
		return nil, nil
	}
	projectID, ok := r.projectIDForWorkingDir(wd)
	if !ok {
		return nil, nil
	}
	run, ok := provider.GetRunGraphQL(id)
	if !ok {
		return nil, nil
	}
	if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) != projectID {
		return nil, nil
	}
	r.recordRunDetailView(ctx, run)
	return run, nil
}

func (r *queryResolver) projectIDForWorkingDir(workingDir string) (string, bool) {
	if r.State == nil || workingDir == "" {
		return "", false
	}
	for _, proj := range r.State.GetProjectSnapshots(false) {
		if proj.Path == workingDir {
			return proj.ID, true
		}
	}
	return "", false
}

// recordRunDetailView appends the canonical run_detail_view bead audit event
// the first time a project-scoped run detail is resolved for a specific run.
// Duplicate loads of the same run id are ignored, but distinct runs on the
// same bead remain auditable.
func (r *queryResolver) recordRunDetailView(ctx context.Context, run *Run) {
	if run == nil || run.BeadID == nil || strings.TrimSpace(*run.BeadID) == "" {
		return
	}
	if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) == "" {
		return
	}
	wd := r.workingDir(ctx)
	if wd == "" {
		return
	}
	if projectID, ok := r.projectIDForWorkingDir(wd); !ok || projectID != strings.TrimSpace(*run.ProjectID) {
		return
	}

	store := bead.NewStore(filepath.Join(wd, ".ddx"))
	if existing, err := store.EventsByKind(*run.BeadID, runDetailViewEventKind); err == nil {
		for _, ev := range existing {
			if strings.Contains(ev.Body, "run_id="+run.ID) {
				return
			}
		}
	}

	identity := operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
	if httpReq := httpRequestFromContext(ctx); httpReq != nil {
		identity = operatorPromptIdentity(httpReq)
	}
	body := fmt.Sprintf(
		"project_id=%s run_id=%s layer=%s visibility=project_membership",
		*run.ProjectID,
		run.ID,
		run.Layer,
	)
	_ = store.AppendEvent(*run.BeadID, bead.BeadEvent{
		Kind:    runDetailViewEventKind,
		Summary: "run detail viewed",
		Body:    body,
		Actor:   identity.actor,
		Source:  "graphql:run",
	})
}

// RunToolCalls is the resolver for the runToolCalls field. Returns the
// normalized tool-call entries persisted at drain time, paginated by
// sequence. Returns an empty connection (not an error) for unknown ids or
// when the backing state provider does not implement RunDetailStateProvider.
func (r *queryResolver) RunToolCalls(ctx context.Context, id string, first *int, after *string) (*RunToolCallConnection, error) {
	provider, ok := r.State.(RunDetailStateProvider)
	if !ok {
		return emptyRunToolCallConnection(), nil
	}
	calls := provider.GetRunToolCallsGraphQL(id)
	return runToolCallConnectionFrom(calls, first, after), nil
}

// RunBundleFile is the resolver for the runBundleFile field. Returns nil
// (not an error) when the path fails canonical-path / whitelist checks or
// the file is not present — the GraphQL response treats nil as 404.
func (r *queryResolver) RunBundleFile(ctx context.Context, id string, path string) (*RunBundleFileContent, error) {
	provider, ok := r.State.(RunDetailStateProvider)
	if !ok {
		return nil, nil
	}
	out, ok := provider.GetRunBundleFileGraphQL(id, path)
	if !ok {
		return nil, nil
	}
	return out, nil
}

func emptyRunToolCallConnection() *RunToolCallConnection {
	return &RunToolCallConnection{Edges: []*RunToolCallEdge{}, PageInfo: &PageInfo{}, TotalCount: 0}
}

func runToolCallConnectionFrom(calls []*RunToolCall, first *int, after *string) *RunToolCallConnection {
	all := make([]*RunToolCallEdge, len(calls))
